// ── SEND EMAIL ────────────────────────────────────────────────────────────────
async function sendReportEmail(customerEmail, bizName, reportHTML, jobId, score) {
  var resendKey = process.env.RESEND_API_KEY;
  if (!resendKey) throw new Error('RESEND_API_KEY not configured');

  var siteUrl  = (process.env.URL || 'https://choive.com').replace(/\/$/, '');
  var resultUrl = siteUrl + '/?jobId=' + encodeURIComponent(jobId);
  var safeFileName = (bizName || 'Report').replace(/[^a-zA-Z0-9\-_]/g, '-').replace(/-+/g, '-').slice(0, 60);

  var emailHtml = [
    '<div style="font-family:Inter,Arial,sans-serif;max-width:560px;margin:0 auto;padding:48px 24px;color:#0C0C0E;background:#fff;">',
    '<div style="margin-bottom:36px;"><img src="' + 'https://choive.com/choive-logo.png' + '" style="height:36px;width:auto;" alt="CHOIVE"/></div>',
    '<h1 style="font-family:Georgia,serif;font-size:26px;font-weight:400;font-style:italic;margin:0 0 14px;line-height:1.2;color:#0C0C0E;">Your AI Selection Report is ready.</h1>',
    '<p style="font-size:14px;line-height:1.85;color:#48484F;margin:0 0 8px;">Your complete CHOIVE Report for <strong>' + esc(bizName) + '</strong> is attached to this email.</p>',
    '<p style="font-size:14px;line-height:1.85;color:#48484F;margin:0 0 8px;">This is your confidential analysis. Do not share it publicly — it contains your exact competitive gaps.</p>',
    '<p style="font-size:14px;line-height:1.85;color:#48484F;margin:0 0 28px;">Your score: <strong style="font-size:18px;font-family:Georgia,serif;color:#0C0C0E;">' + score + '/100</strong></p>',
    '<div style="background:#F5F2EE;padding:22px 26px;margin-bottom:28px;border-left:3px solid #C9A86A;">',
    '<div style="font-size:11px;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:#BBBBC2;margin-bottom:8px;">What\'s inside</div>',
    '<div style="font-size:13px;color:#48484F;line-height:1.85;">',
    '→ Personalised founder letter<br>',
    '→ Score projection — 30, 60, and 90 days<br>',
    '→ What AI currently thinks you are<br>',
    '→ Four pillar breakdown with evidence<br>',
    '→ Platform coverage across ChatGPT, Perplexity, Gemini, Claude<br>',
    '→ AI simulation — real queries, word for word<br>',
    '→ Competitor intelligence<br>',
    '→ Priority actions with consequence blocks<br>',
    '→ Ready-to-use assets<br>',
    '→ 30-day implementation plan',
    '</div></div>',
    '<a href="' + resultUrl + '" style="display:inline-block;background:#C9A86A;color:#0C0C0E;text-decoration:none;font-size:13px;font-weight:700;letter-spacing:0.06em;padding:14px 28px;margin-bottom:28px;">View Your Live Result →</a>',
    '<p style="font-size:12px;color:#BBBBC2;line-height:1.7;margin:0;padding-top:22px;border-top:1px solid #EDEAE5;">',
    'Questions? Reply to this email or contact <a href="mailto:hello@choive.com" style="color:#C9A86A;text-decoration:none;">hello@choive.com</a><br>',
    'CHOIVE· — Be the answer. Not the alternative.',
    '</p></div>'
  ].join('');

  var res = await fetch('https://api.resend.com/emails', {
    method: 'POST',
    headers: { 'Authorization': 'Bearer ' + resendKey, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      from: 'CHOIVE· <hello@choive.com>',
      to: [customerEmail],
      subject: 'Your CHOIVE· Report — ' + bizName,
      html: emailHtml,
      attachments: [{
        filename: `CHOIVE-Report-${safeFileName}.html`,
        content: Buffer.from(reportHTML).toString('base64'),
        contentType: 'text/html'
      }]
    })
  });

  if (!res.ok) {
    var err = await res.json().catch(function() { return {}; });
    throw new Error('Resend failed: ' + (err.message || res.status));
  }
  return await res.json();
}

// ── HANDLER ───────────────────────────────────────────────────────────────────
exports.handler = async function(event) {
  if (event.httpMethod === 'OPTIONS') {
    return { statusCode: 200, headers: CORS, body: '' };
  }
  if (event.httpMethod !== 'POST') {
    return { statusCode: 405, headers: CORS, body: JSON.stringify({ error: 'Method not allowed' }) };
  }

  var body;
  try { body = JSON.parse(event.body || '{}'); }
  catch (_) { return { statusCode: 400, headers: CORS, body: JSON.stringify({ error: 'Invalid JSON' }) }; }

  var jobId         = String(body.jobId || '').trim();
  var customerEmail = String(body.email || '').trim();

  if (!jobId) {
    return { statusCode: 400, headers: CORS, body: JSON.stringify({ error: 'Missing jobId' }) };
  }
  if (!customerEmail || !customerEmail.includes('@')) {
    return { statusCode: 400, headers: CORS, body: JSON.stringify({ error: 'Missing or invalid email' }) };
  }

  console.log('[generate-report] start | jobId:', jobId, '| email:', customerEmail);

  // 1. Fetch diagnostic
  var diagnostic;
  try {
    diagnostic = await getDiagnostic(jobId);
  } catch (err) {
    console.error('[generate-report] getDiagnostic error:', err.message);
    return { statusCode: 500, headers: CORS, body: JSON.stringify({ error: 'Could not fetch diagnostic: ' + err.message }) };
  }

  if (!diagnostic) {
    return { statusCode: 404, headers: CORS, body: JSON.stringify({ error: 'Diagnostic not found: ' + jobId }) };
  }
  if (diagnostic.status !== 'complete') {
    return { statusCode: 400, headers: CORS, body: JSON.stringify({ error: 'Diagnostic not complete. Status: ' + diagnostic.status }) };
  }

  // 2. Build gold report HTML
  var reportHTML;
  try {
    reportHTML = buildReportHTML(diagnostic, jobId);
    console.log('[generate-report] HTML built | length:', reportHTML.length);
  } catch (err) {
    console.error('[generate-report] buildReportHTML error:', err.message, err.stack);
    return { statusCode: 500, headers: CORS, body: JSON.stringify({ error: 'Failed to build report: ' + err.message }) };
  }

  // 3. Email report
  var bizName = safeStr(safeObj(diagnostic.input).name, 'Your Business');
  var score   = safeNum(safeObj(diagnostic.result).overallScore, 0);
  try {
    await sendReportEmail(customerEmail, bizName, reportHTML, jobId, score);
    console.log('[generate-report] emailed to', customerEmail);
  } catch (err) {
    console.error('[generate-report] email error:', err.message);
    return { statusCode: 500, headers: CORS, body: JSON.stringify({ error: 'Failed to send email: ' + err.message }) };
  }

  return {
    statusCode: 200,
    headers: { ...CORS, 'Content-Type': 'application/json' },
    body: JSON.stringify({ ok: true, message: 'Report generated and emailed to ' + customerEmail, jobId: jobId })
  };
};
